#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=2005;
int n,dp[2][N],ans=-0x3f3f3f3f;
struct node
{
	int a,b;
	bool operator<(const node other) const
	{
		return a>other.a;
	}
} num[N];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	memset(dp,128,sizeof(dp));
	for(int i=1;i<=n;i++) cin>>num[i].a>>num[i].b;
	sort(num+1,num+1+n);
	dp[0][1]=0;
	for(int i=1;i<=n;i++)
	{
		for(int j=0;j<=n;j++)
		{
			dp[i%2][j]=max(dp[(i-1)%2][j],dp[(i-1)%2][max(j-num[i].a+1,1)]+num[i].b);
			if(i==n) ans=max(ans,dp[i%2][j]);
		}
	}
	cout<<ans;
	return 0;
}
